// src/components/Contact.jsx
//
// ─── CONFIGURACIÓN EMAILJS ───────────────────────────────────────────────────
// 1. Crea cuenta gratis en https://www.emailjs.com
// 2. Crea un "Email Service" conectado a tu Gmail → copia el Service ID
// 3. Crea un "Email Template" con estas variables:
//      {{from_name}}, {{from_email}}, {{subject}}, {{message}}
//    → copia el Template ID
// 4. En Account → API Keys → copia tu Public Key
// 5. Pega los tres valores abajo:
// ─────────────────────────────────────────────────────────────────────────────
const EMAILJS_SERVICE_ID  = 'TU_SERVICE_ID';   // ej: service_abc123
const EMAILJS_TEMPLATE_ID = 'TU_TEMPLATE_ID';  // ej: template_xyz789
const EMAILJS_PUBLIC_KEY  = 'TU_PUBLIC_KEY';   // ej: aBcDeFgHiJkLmNoP

import { useState, useRef } from 'react';
import { personal } from '../data/portfolio';

const contactLinks = [
  {
    label: 'Correo electrónico',
    val: 'ruben14marco@gmail.com',
    href: `mailto:${personal.contact.email}`,
    icon: MailIcon,
  },
  {
    label: 'LinkedIn',
    val: 'rubén-marco-aa992b234',
    href: personal.contact.linkedin,
    icon: LinkedInIcon,
    external: true,
  },
];

export default function Contact() {
  const formRef = useRef(null);
  const [status, setStatus] = useState('idle'); // idle | sending | success | error
  const [hovered, setHovered] = useState(null);
  const [fields, setFields] = useState({ name: '', email: '', subject: '', message: '' });
  const [errors, setErrors] = useState({});

  const validate = () => {
    const e = {};
    if (!fields.name.trim())    e.name    = 'Introduce tu nombre';
    if (!fields.email.trim())   e.email   = 'Introduce tu email';
    else if (!/\S+@\S+\.\S+/.test(fields.email)) e.email = 'Email no válido';
    if (!fields.subject.trim()) e.subject = 'Introduce un asunto';
    if (!fields.message.trim()) e.message = 'Escribe tu mensaje';
    return e;
  };

  const handleChange = (e) => {
    setFields(prev => ({ ...prev, [e.target.name]: e.target.value }));
    if (errors[e.target.name]) setErrors(prev => ({ ...prev, [e.target.name]: '' }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const validation = validate();
    if (Object.keys(validation).length > 0) { setErrors(validation); return; }

    setStatus('sending');

    try {
      // Carga EmailJS dinámicamente (sin instalar nada)
      const emailjs = await import('https://cdn.jsdelivr.net/npm/@emailjs/browser@4/+esm');

      await emailjs.send(
        EMAILJS_SERVICE_ID,
        EMAILJS_TEMPLATE_ID,
        {
          from_name:  fields.name,
          from_email: fields.email,
          subject:    fields.subject,
          message:    fields.message,
          to_email:   personal.contact.email,
        },
        EMAILJS_PUBLIC_KEY
      );

      setStatus('success');
      setFields({ name: '', email: '', subject: '', message: '' });
    } catch (err) {
      console.error('EmailJS error:', err);
      setStatus('error');
    }
  };

  return (
    <section id="contact" style={s.section}>
      <div style={s.inner}>

        <div className="reveal">
          <p style={s.label}>Contacto</p>
          <h2 style={s.title}>Hablemos</h2>
          <p style={s.sub}>¿Tienes una oportunidad en mente? Escríbeme y te respondo.</p>
        </div>

        <div style={s.grid}>

          {/* ── Columna izquierda ── */}
          <div className="reveal" style={s.leftCol}>

            <p style={s.leftText}>
              Estoy buscando mi primer rol como desarrollador. Si buscas alguien con ganas de aprender,
              adaptarse rápido y aportar desde el primer día — escríbeme.
            </p>

            <div style={s.linksList}>
              {contactLinks.map((item, i) => {
                const Icon = item.icon;
                return (
                  <a
                    key={i}
                    href={item.href}
                    target={item.external ? '_blank' : undefined}
                    rel="noreferrer"
                    style={{ ...s.contactLink, ...(hovered === i ? s.contactLinkHover : {}) }}
                    onMouseEnter={() => setHovered(i)}
                    onMouseLeave={() => setHovered(null)}
                  >
                    <div style={s.contactIconWrap}>
                      <Icon size={18} />
                    </div>
                    <div>
                      <div style={s.contactLinkLabel}>{item.label}</div>
                      <div style={s.contactLinkVal}>{item.val}</div>
                    </div>
                    <span style={s.contactArrow}>→</span>
                  </a>
                );
              })}
            </div>

            <div style={s.availBadge}>
              <span style={s.availDot} />
              Disponible para nuevas oportunidades
            </div>

          </div>

          {/* ── Formulario ── */}
          <div className="reveal reveal-delay-2">
            <form ref={formRef} onSubmit={handleSubmit} noValidate style={s.form}>

              <div style={s.row}>
                <Field
                  label="Nombre" name="name" type="text"
                  placeholder="Juan García"
                  value={fields.name} onChange={handleChange}
                  error={errors.name}
                />
                <Field
                  label="Email" name="email" type="email"
                  placeholder="juan@empresa.com"
                  value={fields.email} onChange={handleChange}
                  error={errors.email}
                />
              </div>

              <Field
                label="Asunto" name="subject" type="text"
                placeholder="Oportunidad de trabajo"
                value={fields.subject} onChange={handleChange}
                error={errors.subject}
              />

              <Field
                label="Mensaje" name="message" type="textarea"
                placeholder="Cuéntame sobre la oportunidad..."
                value={fields.message} onChange={handleChange}
                error={errors.message}
                rows={5}
              />

              {/* Botón de envío */}
              <button
                type="submit"
                disabled={status === 'sending'}
                style={{
                  ...s.submit,
                  ...(status === 'sending' ? s.submitDisabled : {}),
                }}
                onMouseEnter={e => { if (status !== 'sending') { e.currentTarget.style.background = 'var(--accent2)'; e.currentTarget.style.transform = 'translateY(-2px)'; }}}
                onMouseLeave={e => { e.currentTarget.style.background = status === 'sending' ? 'var(--text3)' : 'var(--accent)'; e.currentTarget.style.transform = 'none'; }}
              >
                {status === 'sending' ? 'Enviando...' : 'Enviar mensaje →'}
              </button>

              {/* Feedback */}
              {status === 'success' && (
                <div style={s.feedbackSuccess}>
                  Mensaje enviado correctamente. Te respondo pronto.
                </div>
              )}
              {status === 'error' && (
                <div style={s.feedbackError}>
                  Hubo un error al enviar. Escríbeme directamente a{' '}
                  <a href={`mailto:${personal.contact.email}`} style={{ color: 'var(--accent2)' }}>
                    {personal.contact.email}
                  </a>
                </div>
              )}

            </form>
          </div>
        </div>
      </div>
    </section>
  );
}

// ── Campo de formulario reutilizable ──
function Field({ label, name, type, placeholder, value, onChange, error, rows }) {
  const [focused, setFocused] = useState(false);

  const inputStyle = {
    ...s.input,
    borderColor: error ? 'rgba(232,58,58,0.6)' : focused ? 'rgba(232,58,58,0.5)' : 'var(--border2)',
    boxShadow: focused && !error ? '0 0 0 3px rgba(232,58,58,0.08)' : 'none',
  };

  return (
    <div style={s.formGroup}>
      <label style={s.formLabel}>{label}</label>
      {type === 'textarea' ? (
        <textarea
          name={name} rows={rows}
          placeholder={placeholder}
          value={value} onChange={onChange}
          onFocus={() => setFocused(true)}
          onBlur={() => setFocused(false)}
          style={{ ...inputStyle, resize: 'vertical' }}
        />
      ) : (
        <input
          name={name} type={type}
          placeholder={placeholder}
          value={value} onChange={onChange}
          onFocus={() => setFocused(true)}
          onBlur={() => setFocused(false)}
          style={inputStyle}
        />
      )}
      {error && <span style={s.errorMsg}>{error}</span>}
    </div>
  );
}

